import{_ as r,o as n,c as i,ai as e}from"./chunks/framework.CaiDwmc7.js";const S=JSON.parse('{"title":"Spring 核心原理（IoC 与 AOP）","description":"","frontmatter":{},"headers":[],"relativePath":"framework/spring-core.md","filePath":"framework/spring-core.md"}'),t={name:"framework/spring-core.md"};function s(g,o,l,a,c,p){return n(),i("div",null,[...o[0]||(o[0]=[e('<h1 id="spring-核心原理-ioc-与-aop" tabindex="-1">Spring 核心原理（IoC 与 AOP） <a class="header-anchor" href="#spring-核心原理-ioc-与-aop" aria-label="Permalink to “Spring 核心原理（IoC 与 AOP）”">​</a></h1><hr><h3 id="❓-面试官-能谈谈你对-spring-ioc-控制反转-和-di-依赖注入-的理解吗" tabindex="-1">❓ 面试官：能谈谈你对 Spring IoC（控制反转）和 DI（依赖注入）的理解吗？ <a class="header-anchor" href="#❓-面试官-能谈谈你对-spring-ioc-控制反转-和-di-依赖注入-的理解吗" aria-label="Permalink to “❓ 面试官：能谈谈你对 Spring IoC（控制反转）和 DI（依赖注入）的理解吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>IoC（控制反转）</strong>是一种设计思想。把创建和管理对象的<strong>控制权</strong>，从我们自己写的代码里，<strong>反转</strong>交给了 Spring 容器去管理。</li><li><strong>DI（依赖注入）</strong>是 IoC 的具体实现方式。Spring 容器在运行期间，动态地将某个对象所依赖的其他对象（比如 Controller 依赖 Service）<strong>注入</strong>到该对象中。</li></ul><p><strong>📝 详细原理解析与实战：</strong></p><ol><li><strong>没有 IoC 的痛点</strong>： <ul><li>以前我们写代码：<code>UserService service = new UserServiceImpl();</code>。</li><li>耦合度极高：如果哪天实现类换成了 <code>UserNewServiceImpl</code>，我们需要满项目去全局搜索并修改 <code>new</code> 关键字。</li></ul></li><li><strong>有了 IoC 之后（解耦）</strong>： <ul><li>我们只需要打个注解 <code>@RestController</code> / <code>@Service</code>。</li><li>Spring 启动时，会去扫描这些注解，利用<strong>反射机制</strong>自动帮我们 <code>new</code> 出这些对象（称为 Bean），并放进一个叫<strong>大 Map（单例池）</strong> 的容器里。</li><li>当我们需要用 Service 时，只需加个 <code>@Autowired</code>，Spring 就会自动从 Map 里把建好的 Bean 拿出来塞给我们。</li></ul></li><li><strong>DI 的三种注入方式</strong>： <ul><li><code>@Autowired</code> 字段注入（最常用，但不被官方推荐，容易产生循环依赖且不好写单元测试）。</li><li><strong>构造器注入（Spring 官方极力推荐）</strong>：强制依赖，保证 Bean 初始化时所有依赖都已就绪。</li><li>Setter 方法注入。</li></ul></li></ol><hr><h3 id="❓-面试官-spring-的-aop-面向切面编程-是什么-你们在项目里怎么用的" tabindex="-1">❓ 面试官：Spring 的 AOP（面向切面编程）是什么？你们在项目里怎么用的？ <a class="header-anchor" href="#❓-面试官-spring-的-aop-面向切面编程-是什么-你们在项目里怎么用的" aria-label="Permalink to “❓ 面试官：Spring 的 AOP（面向切面编程）是什么？你们在项目里怎么用的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> AOP 的核心目的是<strong>“将非业务的通用逻辑（如日志、权限、事务）从核心业务代码中剥离出来，实现无侵入式的增强”</strong>。它的底层实现原理是<strong>动态代理</strong>。</p><p><strong>📝 详细原理解析与应用场景：</strong></p><ol><li><p><strong>通俗理解</strong>：</p><ul><li>你写了 100 个接口，老板突然要求：每个接口被调用时，都要打印一下入参、出参和接口耗时。</li><li>如果不用 AOP：你需要修改这 100 个接口的源码，复制粘贴 100 遍日志代码（灾难）。</li><li>如果用 AOP：你只需要写一个<strong>切面类（Aspect）</strong>，定义一个<strong>切点（Pointcut，指定拦截哪些包下的方法）</strong>，然后写一个<strong>环绕通知（@Around）</strong>。Spring 会自动在这些方法执行前后，帮你“织入”这段日志代码。</li></ul></li><li><p><strong>实战应用场景（高频考点）</strong>：</p><ul><li><strong>全局日志记录</strong>：记录接口操作人、时间、耗时、异常信息，存入数据库。</li><li><strong>权限校验</strong>：自定义一个 <code>@RequireRole(&quot;admin&quot;)</code> 注解，利用 AOP 拦截该注解，判断当前用户是否有权限。</li><li><strong>分布式锁</strong>：自定义 <code>@RedisLock</code> 注解，AOP 切面里实现 Redisson 加锁和释放锁的逻辑。</li><li><strong>Spring 声明式事务（<code>@Transactional</code>）</strong>：这是 Spring 官方自己写的最牛逼的 AOP 切面。</li></ul></li></ol><hr><h3 id="❓-面试官-既然-aop-底层是动态代理-能讲讲-jdk-动态代理和-cglib-动态代理的区别吗-【中级】" tabindex="-1">❓ 面试官：既然 AOP 底层是动态代理，能讲讲 JDK 动态代理和 CGLib 动态代理的区别吗？【中级】 <a class="header-anchor" href="#❓-面试官-既然-aop-底层是动态代理-能讲讲-jdk-动态代理和-cglib-动态代理的区别吗-【中级】" aria-label="Permalink to “❓ 面试官：既然 AOP 底层是动态代理，能讲讲 JDK 动态代理和 CGLib 动态代理的区别吗？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>JDK 动态代理</strong>：基于<strong>接口</strong>实现。它通过反射，在内存里动态生成一个实现了目标接口的代理类。如果你的类没有实现任何接口，就不能用 JDK 代理。</li><li><strong>CGLib 动态代理</strong>：基于<strong>继承</strong>实现。它通过底层字节码技术（ASM），动态生成一个目标类的<strong>子类</strong>。即使目标类没有实现接口也能代理，但如果目标方法是 <code>final</code> 或 <code>private</code> 的，则无法被重写代理。</li></ul><p><strong>📝 Spring 里的选择策略：</strong></p><ul><li>在 Spring 5.x（Spring Boot 2.x）及以后的版本中，<strong>默认情况下全部使用 CGLib 动态代理</strong>（即使你实现了接口）。因为 CGLib 性能更好，且不需要强制开发者去写接口。如果你非要强制使用 JDK 代理，需要配置 <code>spring.aop.proxy-target-class=false</code>。</li></ul><hr><h3 id="❓-面试官-请简述一下-spring-bean-的生命周期-【中高级】" tabindex="-1">❓ 面试官：请简述一下 Spring Bean 的生命周期？【中高级】 <a class="header-anchor" href="#❓-面试官-请简述一下-spring-bean-的生命周期-【中高级】" aria-label="Permalink to “❓ 面试官：请简述一下 Spring Bean 的生命周期？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Spring Bean 的生命周期非常复杂，但核心骨架就 4 步：<strong>实例化（new） $\\rightarrow$ 属性赋值（DI 注入） $\\rightarrow$ 初始化（init） $\\rightarrow$ 销毁（destroy）</strong>。</p><p><strong>📝 详细的扩展点（背住这几个关键接口即可）：</strong> 面试官其实不想听你背 10 几步的源码，他想听的是你知不知道<strong>怎么在 Bean 创建的过程中去“插手/干预”</strong>。</p><ol><li><strong>实例化（Instantiation）</strong>：Spring 利用反射调用构造方法，在内存中 <code>new</code> 出一个空壳对象。</li><li><strong>属性赋值（Populate）</strong>：解析 <code>@Autowired</code> 等注解，把依赖的其他 Bean 注入进来。</li><li><strong>初始化（Initialization，最重要，扩展点全在这里）</strong>： <ul><li>如果实现了 <code>Aware</code> 接口（如 <code>BeanNameAware</code>），会把 Spring 容器的一些底层组件传给你。</li><li>执行 <strong><code>BeanPostProcessor.postProcessBeforeInitialization</code>（前置处理器）</strong>：可以在初始化前修改 Bean 属性。</li><li>执行自定义的初始化方法（被 <code>@PostConstruct</code> 注解修饰的方法，或者 <code>InitializingBean</code> 接口的 <code>afterPropertiesSet</code>）。</li><li>执行 <strong><code>BeanPostProcessor.postProcessAfterInitialization</code>（后置处理器）</strong>：<strong>（重点！）Spring AOP 就是在这里发生的</strong>。如果是被切面拦截的类，Spring 会在这个阶段生成一个代理对象，并把代理对象扔进单例池，替换掉原来的原生对象。</li></ul></li><li><strong>使用阶段</strong>：对象静静地躺在单例池（大 Map）里供别人调用。</li><li><strong>销毁（Destruction）</strong>：Spring 容器关闭时，执行 <code>@PreDestroy</code> 标注的方法进行资源清理。</li></ol>',27)])])}const h=r(t,[["render",s]]);export{S as __pageData,h as default};
